## 2. Cloud‑Native Remediation Using AWS CDK (TypeScript)

Below is a **minimal, secure‑by‑design CDK construct** that implements many of the hardening controls listed above. The code follows the **OWASP Secure Coding Guidelines** and avoids common CWEs (e.g., no hard‑coded secrets, least‑privilege IAM, encryption‑at‑rest).

```typescript
import * as cdk from 'aws-cdk-lib';
import {
  Stack,
  StackProps,
  RemovalPolicy,
  Duration,
} from 'aws-cdk-lib';
import * as s3 from 'aws-cdk-lib/aws-s3';
import * as iam from 'aws-cdk-lib/aws-iam';
import * as lambda from 'aws-cdk-lib/aws-lambda';
import * as logs from 'aws-cdk-lib/aws-logs';
import * as config from 'aws-cdk-lib/aws-config';
import * as guardduty from 'aws-cdk-lib/aws-guardduty';

export class SecureWorkloadStack extends Stack {
  constructor(scope: cdk.App, id: string, props?: StackProps) {
    super(scope, id, props);

    /** 1️⃣ S3 bucket – encrypted, versioned, no public access */
    const dataBucket = new s3.Bucket(this, 'DataBucket', {
      encryption: s3.BucketEncryption.S3_MANAGED, // AES‑256
      versioned: true,
      blockPublicAccess: s3.BlockPublicAccess.BLOCK_ALL,
      enforceSSL: true,
      removalPolicy: RemovalPolicy.RETAIN, // never auto‑delete
      lifecycleRules: [
        {
          enabled: true,
          abortIncompleteMultipartUploadAfter: Duration.days(7),
        },
      ],
    });

    /** 2️⃣ IAM role for Lambda – least privilege */
    const lambdaRole = new iam.Role(this, 'SecureLambdaRole', {
      assumedBy: new iam.ServicePrincipal('lambda.amazonaws.com'),
      description: 'Role for secure data‑exfiltration detection Lambda',
    });

    // Grant only the permissions the function truly needs
    lambdaRole.addToPolicy(
      new iam.PolicyStatement({
        effect: iam.Effect.ALLOW,
        actions: [
          's3:GetObject',
          's3:ListBucket',
          'logs:CreateLogGroup',
          'logs:CreateLogStream',
          'logs:PutLogEvents',
        ],
        resources: [
          dataBucket.bucketArn,
          `${dataBucket.bucketArn}/*`,
          `${logs.LogGroup.LOG_GROUP_ARN}*`,
        ],
      })
    );

    /** 3️⃣ Lambda function – code signing required, no environment secrets */
    const detectorFn = new lambda.Function(this, 'DetectAnomalousLambda', {
      runtime: lambda.Runtime.NODEJS_18_X,
      handler: 'index.handler',
      code: lambda.Code.fromAsset('lambda'), // <-- keep code out of repo, use CI pipeline
      role: lambdaRole,
      timeout: Duration.seconds(30),
      logRetention: logs.RetentionDays.ONE_WEEK,
      // Enforce code signing (requires a CodeSigningConfig resource)
      // See https://docs.aws.amazon.com/lambda/latest/dg/configuration-codesigning.html
    });

    /** 4️⃣ GuardDuty detector – enable if not already */
    new guardduty.CfnDetector(this, 'GuardDutyDetector', {
      enable: true,
    });

    /** 5️⃣ AWS Config rules – auto‑remediate public S3 buckets */
    new config.ManagedRule(this, 'S3PublicReadProhibited', {
      identifier: 'S3_BUCKET_PUBLIC_READ_PROHIBITED',
    });

    new config.ManagedRule(this, 'IAMNoFullAccess', {
      identifier: 'IAM_POLICY_NO_STATEMENTS_WITH_FULL_ACCESS',
    });

    /** 6️⃣ CloudTrail – data events for S3 & Lambda (in separate stack for brevity) */
    // In production you would create a dedicated Trail construct with
    // encryption, multi‑region, and an immutable S3 destination.
  }
}
