#### Secure CDK Example – Least‑Privilege Role for a SWIFT‑API Lambda

```ts
import * as cdk from 'aws-cdk-lib';
import { aws_iam as iam, aws_lambda as lambda } from 'aws-cdk-lib';

export class SwiftApiStack extends cdk.Stack {
  constructor(scope: cdk.App, id: string, props?: cdk.StackProps) {
    super(scope, id, props);

    // 1️⃣  Create a role with the minimal permissions the Lambda needs
    const swiftRole = new iam.Role(this, 'SwiftApiRole', {
      assumedBy: new iam.ServicePrincipal('lambda.amazonaws.com'),
      // Enforce MFA for any human who might assume this role (defense‑in‑depth)
      // Note: MFA condition only applies when a user assumes the role, not for the Lambda itself.
      // This is safe because the Lambda uses its own role credentials.
      inlinePolicies: {
        // Allow read‑only access to the secret that holds SWIFT credentials
        SecretsRead: new iam.PolicyDocument({
          statements: [
            new iam.PolicyStatement({
              actions: ['secretsmanager:GetSecretValue'],
              resources: ['arn:aws:secretsmanager:*:*:secret:swift/*'],
            }),
          ],
        }),
        // Allow the Lambda to write audit logs to CloudWatch
        CloudWatchLogs: new iam.PolicyDocument({
          statements: [
            new iam.PolicyStatement({
              actions: [
                'logs:CreateLogGroup',
                'logs:CreateLogStream',
                'logs:PutLogEvents',
              ],
              resources: ['*'],
            }),
          ],
        }),
      },
    });

    // 2️⃣  Deploy the Lambda using the role
    new lambda.Function(this, 'SwiftApiHandler', {
      runtime: lambda.Runtime.NODEJS_20_X,
      handler: 'index.handler',
      code: lambda.Code.fromAsset('lambda'),
      role: swiftRole,
      // No environment variables with secrets – they are fetched at runtime from Secrets Manager
      environment: {
        // Example of a non‑secret config value
        LOG_LEVEL: 'info',
      },
    });
  }
}
```

*Why this is safe*  

* No hard‑coded credentials.  
* The role grants **only** `secretsmanager:GetSecretValue` on the specific secret and CloudWatch logging rights.  
* The policy is scoped to a single secret ARN → eliminates CWE‑284 (excessive privileges).  

