**Sample Lambda (Python 3.11) – safe, no hard‑coded secrets**

```python
import json
import boto3
import os
from datetime import datetime, timedelta

wafv2 = boto3.client('wafv2')
cloudwatch = boto3.client('cloudwatch')
log = boto3.client('logs')

# Environment variables set in the Lambda configuration
IP_SET_ARN = os.getenv('IP_SET_ARN')
WEB_ACL_ARN = os.getenv('WEB_ACL_ARN')
ALERT_THRESHOLD = int(os.getenv('ALERT_THRESHOLD', '2000'))  # requests per 5 min

def lambda_handler(event, context):
    # Event is a GuardDuty finding or CloudWatch alarm
    src_ip = event['detail']['resource']['instanceDetails']['networkInterfaces'][0]['ipv4Addresses'][0]

    # Add IP to WAF IP set (idempotent)
    resp = wafv2.get_ip_set(Name='KnownScannerIPs', Scope='REGIONAL', Id=IP_SET_ARN.split('/')[-1])
    addresses = resp['IPSet']['Addresses']
    if src_ip not in addresses:
        addresses.append(f"{src_ip}/32")
        wafv2.update_ip_set(
            Name='KnownScannerIPs',
            Scope='REGIONAL',
            Id=IP_SET_ARN.split('/')[-1],
            Addresses=addresses,
            LockToken=resp['LockToken']
        )
    # Emit a custom CloudWatch metric for visibility
    cloudwatch.put_metric_data(
        Namespace='Security/TimedScans',
        MetricData=[{
            'MetricName': 'BlockedScannerIP',
            'Timestamp': datetime.utcnow(),
            'Value': 1,
            'Dimensions': [{'Name': 'SourceIP', 'Value': src_ip}]
        }]
    )
    return {'status': 'IP added to block list'}
```

*Security notes*:  
- The Lambda uses **least‑privilege IAM** (`wafv2:GetIPSet`, `wafv2:UpdateIPSet`, `cloudwatch:PutMetricData`).  
