### Example of a concrete, secure remediation snippet (AWS CDK)

If the investigation reveals that an IAM role allowed `sts:AssumeRole` from any AWS account (a classic “trust‑any‑principal” misconfiguration), the following **CDK** construct safely tightens the trust policy. The code follows **secure‑by‑design** guidelines:

```typescript
import * as cdk from 'aws-cdk-lib';
import { Role, ServicePrincipal, PolicyStatement, Effect } from 'aws-cdk-lib/aws-iam';

export class HardenedRoleStack extends cdk.Stack {
  constructor(scope: cdk.App, id: string, props?: cdk.StackProps) {
    super(scope, id, props);

    // Replace <ACCOUNT_ID> and <TRUSTED_PRINCIPAL> with verified values only.
    const trustedAccount = cdk.Fn.importValue('TrustedAccountId'); // immutable import
    const role = new Role(this, 'SecureProcessingRole', {
      assumedBy: new ServicePrincipal('lambda.amazonaws.com', {
        conditions: {
          // Restrict to a specific AWS account and optional external ID
          StringEquals: {
            'aws:PrincipalAccount': trustedAccount,
          },
          // Optional: enforce MFA for role assumption (CWE‑307)
          Bool: {
            'aws:MultiFactorAuthPresent': 'true',
          },
        },
      }),
      description: 'Role with least‑privilege permissions for data processing',
    });

    // Example least‑privilege permission
    role.addToPolicy(
      new PolicyStatement({
        effect: Effect.ALLOW,
        actions: ['s3:GetObject', 's3:PutObject'],
        resources: ['arn:aws:s3:::my-secure-bucket/*'],
      })
    );

    // Explicit deny for any other principal (defense‑in‑depth)
    role.addToPolicy(
      new PolicyStatement({
        effect: Effect.DENY,
        actions: ['*'],
        resources: ['*'],
        principals: [new cdk.aws_iam.AnyPrincipal()],
