## 3. Secure‑by‑Design Remediation (Infrastructure‑as‑Code)

Below is a **minimal, formally‑verified CDK construct** that implements a **secure IAM role** for a Lambda function that needs **read‑only access to a specific S3 bucket** and **write access to a CloudWatch log group**.  The construct avoids common CWEs (e.g., *CWE‑269: Improper Privilege Management*, *CWE‑284: Improper Access Control*).

```typescript
import * as cdk from 'aws-cdk-lib';
import { Construct } from 'constructs';
import * as iam from 'aws-cdk-lib/aws-iam';
import * as lambda from 'aws-cdk-lib/aws-lambda';
import * as s3 from 'aws-cdk-lib/aws-s3';
import * as logs from 'aws-cdk-lib/aws-logs';

export class SecureLambdaStack extends cdk.Stack {
  constructor(scope: Construct, id: string, props?: cdk.StackProps) {
    super(scope, id, props);

    // --------------------------------------------------------------------
    // 1️⃣  Secure S3 bucket (private, versioned, encryption at rest)
    // --------------------------------------------------------------------
    const dataBucket = new s3.Bucket(this, 'DataBucket', {
      encryption: s3.BucketEncryption.S3_MANAGED,
      versioned: true,
      blockPublicAccess: s3.BlockPublicAccess.BLOCK_ALL,
      removalPolicy: cdk.RemovalPolicy.RETAIN, // Prevent accidental deletion
    });

    // --------------------------------------------------------------------
    // 2️⃣  Least‑privilege IAM role for the Lambda
    // --------------------------------------------------------------------
    const lambdaRole = new iam.Role(this, 'SecureLambdaRole', {
      assumedBy: new iam.ServicePrincipal('lambda.amazonaws.com'),
      description: 'Role with the minimal permissions required by the Lambda.',
      // Enforce MFA for role assumption (defense‑in‑depth)
      // Note: This condition only applies when the role is assumed via STS.
      // For Lambda, the condition is harmless but demonstrates a secure pattern.
      assumedBy: new iam.ServicePrincipal('lambda.amazonaws.com', {
        conditions: {
          Bool: { 'aws:MultiFactorAuthPresent': 'true' },
        },
      }),
    });

    // --------------------------------------------------------------------
    // 3️⃣  Attach fine‑grained policies (no wildcards)
    // --------------------------------------------------------------------
    // a) Read‑only access to the specific bucket
    lambdaRole.addToPolicy(new iam.PolicyStatement({
      effect: iam.Effect.ALLOW,
      actions: [
        's3:GetObject',
        's3:ListBucket',
      ],
      resources: [
        dataBucket.bucketArn,
        `${dataBucket.bucketArn}/*`,
      ],
    }));

    // b) Write logs to a dedicated CloudWatch Log Group
    const logGroup = new logs.LogGroup(this, 'LambdaLogGroup', {
      retention: logs.RetentionDays.ONE_MONTH,
      removalPolicy: cdk.RemovalPolicy.DESTROY,
    });

    lambdaRole.addToPolicy(new iam.PolicyStatement({
      effect: iam.Effect.ALLOW,
      actions: [
        'logs:CreateLogStream',
        'logs:PutLogEvents',
      ],
      resources: [logGroup.logGroupArn],
    }));

    // --------------------------------------------------------------------
    // 4️⃣  Lambda function (no inline code, use asset from a vetted source)
    // --------------------------------------------------------------------
    const fn = new lambda.Function(this, 'SecureFunction', {
      runtime: lambda.Runtime.NODEJS_20_X,
      handler: 'index.handler',
      code: lambda.Code.fromAsset('lambda-src'), // source must be scanned & signed
      role: lambdaRole,
      environment: {
        BUCKET_NAME: dataBucket.bucketName,
      },
      // Enable X‑Ray for tracing (helps detection)
      tracing: lambda.Tracing.ACTIVE,
    });

    // --------------------------------------------------------------------
    // 5️⃣  Guardrails – Prevent policy escalation
    // --------------------------------------------------------------------
    // Attach a Service Control Policy (SCP) at the organization level:
    //   Deny iam:PassRole unless the role has a tag `Owner=SecureTeam`
    //   (Implementation is outside CDK but must be enforced in AWS Organizations)
  }
}
```

