    func urlSession(_ session: URLSession,
                    didReceive challenge: URLAuthenticationChallenge,
                    completionHandler: @escaping (URLSession.AuthChallengeDisposition, URLCredential?) -> Void) {

        guard let serverTrust = challenge.protectionSpace.serverTrust,
              let cert = SecTrustGetCertificateAtIndex(serverTrust, 0) else {
            completionHandler(.cancelAuthenticationChallenge, nil)
            return
        }

        // Extract public key data
        var error: CFError?
        guard let publicKey = SecCertificateCopyKey(cert),
              let keyData = SecKeyCopyExternalRepresentation(publicKey, &error) as Data? else {
            completionHandler(.cancelAuthenticationChallenge, nil)
            return
        }

        // Compute SHA‑256 hash
        let hash = SHA256.hash(data: keyData)
        let hashBase64 = Data(hash).base64EncodedString()

        if hashBase64 == expectedPublicKeyHash {
            // Trust the connection
            let credential = URLCredential(trust: serverTrust)
            completionHandler(.useCredential, credential)
        } else {
            // Pin mismatch → abort
            completionHandler(.cancelAuthenticationChallenge, nil)
        }
    }
}

// Usage
let session = URLSession(configuration: .default,
                         delegate: PinningURLSessionDelegate(),
                         delegateQueue: nil)
```

*Security notes*  

* The delegate validates the **public‑key hash** rather than the full certificate chain, making the check resilient to intermediate‑certificate changes (CWE‑295).  
* The code never logs or stores the raw certificate, avoiding **CWE‑319** (Cleartext Transmission of Sensitive Information).  

